package main

import (
    "fmt"
    "log"

    "gorm.io/driver/sqlite"
    "gorm.io/gorm"
    "gorm.io/gorm/logger"
)

// ---- Models ----
type Player struct {
    ID     uint   `gorm:"primaryKey"`
    Name   string `gorm:"not null"`
    Health int    `gorm:"default:100"`
    Attack int    `gorm:"default:10"`
    Level  int    `gorm:"default:1"`
}

func (p Player) String() string {
    return fmt.Sprintf("Player{ID: %d, Name: %s, HP: %d, ATK: %d, Lv: %d}",
        p.ID, p.Name, p.Health, p.Attack, p.Level)
}

type Item struct {
    ID    uint    `gorm:"primaryKey"`
    Name  string  `gorm:"not null"`
    Price float64
}

func main() {
    // ---- Connect ----
    db, err := gorm.Open(sqlite.Open("./gorm.db"), &gorm.Config{
        Logger: logger.Default.LogMode(logger.Silent),
    })
    if err != nil {
        log.Fatal(err)
    }

    // ---- Auto migrate ----
    db.AutoMigrate(&Player{}, &Item{})

    // ---- Create ----
    fmt.Println("=== CREATE ===")
    p1 := Player{Name: "Hero", Health: 100, Attack: 20, Level: 5}
    db.Create(&p1)
    fmt.Printf("Created: %v\n", p1)

    p2 := Player{Name: "Aragorn", Health: 120, Attack: 25, Level: 8}
    db.Create(&p2)
    fmt.Printf("Created: %v\n", p2)

    // ---- Read ----
    fmt.Println("\n=== READ ===")
    var players []Player
    db.Find(&players)
    fmt.Printf("All players: %v\n", players)

    var p Player
    db.First(&p, 1)
    fmt.Printf("Player with ID 1: %v\n", p)

    // ---- Where conditions ----
    var strongPlayers []Player
    db.Where("health > ?", 100).Find(&strongPlayers)
    fmt.Printf("Players with HP > 100: %v\n", strongPlayers)

    // ---- Update ----
    fmt.Println("\n=== UPDATE ===")
    db.Model(&p).Updates(Player{Name: "Hero the Brave", Health: 150, Level: 6})
    fmt.Printf("Updated: %v\n", p)

    // ---- Delete ----
    fmt.Println("\n=== DELETE ===")
    db.Delete(&p2)
    fmt.Println("Deleted player with ID 2")

    // ---- Final read ----
    var final []Player
    db.Find(&final)
    fmt.Printf("\nFinal players: %v\n", final)

    // ---- Create with association ----
    fmt.Println("\n=== ITEMS ===")
    items := []Item{
        {Name: "Sword", Price: 50.0},
        {Name: "Shield", Price: 40.0},
        {Name: "Potion", Price: 10.0},
    }
    db.Create(&items)
    for _, item := range items {
        fmt.Printf("Item: %v\n", item)
    }

    // ---- Query with conditions ----
    var cheapItems []Item
    db.Where("price < ?", 30).Find(&cheapItems)
    fmt.Printf("\nItems under $30: %v\n", cheapItems)
}

