package main

import (
    "fmt"
    "log"

    "gorm.io/driver/sqlite"
    "gorm.io/gorm"
    "gorm.io/gorm/logger"
)

type Product struct {
    ID    uint
    Name  string
    Price float64
}

func main() {
    db, err := gorm.Open(sqlite.Open("./products.db"), &gorm.Config{
        Logger: logger.Default.LogMode(logger.Silent),
    })
    if err != nil {
        log.Fatal(err)
    }

    db.AutoMigrate(&Product{})

    // Create
    products := []Product{
        {Name: "Sword", Price: 50.0},
        {Name: "Shield", Price: 40.0},
        {Name: "Potion", Price: 10.0},
    }
    db.Create(&products)
    fmt.Println("Created products:", products)

    // Find all
    var all []Product
    db.Find(&all)
    fmt.Println("All products:", all)

    // Where
    var cheap []Product
    db.Where("price < ?", 30).Find(&cheap)
    fmt.Println("Cheap products:", cheap)

    // Update
    var p Product
    db.First(&p, 1)
    db.Model(&p).Update("price", 55.0)
    fmt.Println("Updated product 1:", p)

    // Delete
    var p2 Product
    db.First(&p2, 3)
    db.Delete(&p2)
    fmt.Println("Deleted product 3")

    // Final
    var final []Product
    db.Find(&final)
    fmt.Println("Final products:", final)
}
